ToolCallDeclareAction.tc_definition:
\{
        				"type": "function",
        				"function": {
            				"name": "move_to_relative",
							"supports_parallel": true,
            				"description": "Use this tool to move the robot by specifying a distance and heading. Returns a result property specifying one of: success, failed.  On failure the overall tool call sequence must be aborted. Here are examples of how you can use this tool: to move the forward: distance = (positive distance amount), heading = 0. to move the backwards: distance = (negative distance amount), heading = 0. to turn left: distance = 0, heading = 90. to turn right: distance = 0, heading = -90. to rotate 360 degrees, you must split the operation into two steps: 1. distance=0, heading=180. 2. distance=0, heading=180.",
							"parameters": {
								"type": "object",
								"properties": {
									"movement_params": {
										"type": "object",
										"description": "The distance and change in heading.",
										"properties": {
											"distance": {
												"type": "number",
												"description": "Distance to move in meters."
											},
											"heading": {
												"type": "number",
												"description": "The change in heading in degrees. An increase turns left (counter-clockwise) and a decrease turns right (clockwise). "
											}
										},
										"required": ["distance", "heading"]
									}
								},
								"required": ["movement_params"]
							},
							"returns": {
								"type": "object",
								"properties": {
									"result": {
										"type": "string",
										"enum": ["success", "failed"]
									}
								}
							}								
						}
					\}

\{
        				"type": "function",
        				"function": {
            				"name": "move_to_absolute",
							"supports_parallel": true,
            				"description": "Use this tool to move the robot to a specified absolute position and then turn to the specified yaw orientation.  Returns a result property specifying one of: success, failed.  On failure the overall tool call sequence must be aborted. Do not use this tool for relative movements, instead use the move_to_relative tool.",
							"parameters": {
								"type": "object",
								"properties": {
									"position_and_orientation": {
										"type": "object",
										"description": "The exact spatial placement coordinates and rotational yaw angle.",
										"properties": {
											"x": {
												"type": "number",
												"description": "The x-axis coordinate position in meter."
											},
											"y": {
												"type": "number",
												"description": "The y-axis coordinate position in meters."
											},
											"yaw": {
												"type": "number",
												"description": "Ending yaw after moving to the position.  The yaw is rotational angle around the z-axis (vertical) in degrees in the range [-180, 180] where an increase in yaw corresponds to turning left and vice versa."
											}
										},
										"required": ["x", "y", "yaw"]
									}
								},
								"required": ["position_and_orientation"]
							},
							"returns": {
								"type": "object",
								"properties": {
									"result": {
										"type": "string",
										"enum": ["success", "failed"]
									}
								}
							}
						}
					\}

\{
        				"type": "function",
        				"function": {
            				"name": "spin_in_place",
							"supports_parallel": true,
            				"description": "Use this tool to rotate the robot by relative angle.  Do not use for turning to a specific heading. Use this tool when you are asked to rotate or when you need to turn to observe what is around you.   Returns a result property specifying one of:  success, failed.  On failure the overall tool call sequence must be aborted. ",
							"parameters": {
								"type": "object",
								"properties": {
									"spin_params": {
										"type": "object",
										"description": "These control the amount and rate of spin.",
										"properties": {
											"angle": {
												"type": "number",
												"description": "Amount to rotate in degrees.  Positive values turn left and vice versa."
											},
											"rate": {
												"type": "number",
												"description": "Rate of turn in radians/sec, range [0.2, 0.7].  Use 0.0 if not specified and a default will be used."
											}
										},
										"required": ["angle", "rate"]
									}
								},
								"required": ["spin_params"]
							},
							"returns": {
								"type": "object",
								"properties": {
									"result": {
										"type": "string",
										"enum": ["success", "failed"]
									}
								}
							}
						}
					\}

\{
        				"type": "function",
        				"function": {
            				"name": "get_map_locations",
							"supports_parallel": false,
            				"description": "Use this tool to get a list of specific locations you can move to.  Use this tool when you need the map location for a place. The output of this tool can be used to lookup the x,y,yaw parameters for passing to the move_to_absolute tool.",
							"returns": {
								"type": "array",
								"description": "An array of locations.",
								"items": {
									"type": "object",
									"properties": {
										"location_name": {
											"type": "string",
											"description": "Name of location"
										},
										"x": {
											"type": "number",
											"description": "X coordinate in meters."
										},
										"y": {
											"type": "number",
											"description": "Y coordinate in meters"
										},
										"yaw": {
											"type": "number",
											"description": "Absolute heading to face"
										}
									}
								}
							}
						}
					\}

\{
        				"type": "function",
        				"function": {
            				"name": "speak",
							"supports_parallel": false,
            				"description": "Use this tool to speak using TTS prior to the final prompt result.  For example, use this during multi-step tool calls.  Dont use this for the final response since that result is always spoken",
							"parameters": {
                				"type": "object",
								"properties": {
                					"text_to_say": {
                    					"type": "string",
                    					"description": "The text to be spoken" }
								},
                				"required": ["text_to_say"]
							},
							"returns": {
								"type": "object",
								"properties": {
									"result": {
										"type": "string",
										"enum": ["success", "failed"]
									}
								}
							}
						}
					\}

\{
        				"type": "function",
        				"function": {
            				"name": "ask_question",
							"supports_parallel": false,
            				"description": "Use this tool to ask the user a question and get their response.",
							"parameters": {
                				"type": "object",
								"properties": {
                					"question": {
                    					"type": "string",
                    					"description": "The text to ask the user"}
								},
                				"required": ["question"]
							},
							"returns": {
								"type": "object",
								"properties": {
									"result": {
										"type": "string",
										"description": "response text"
									}
								}
							}
						}
					\}

\{
        				"type": "function",
        				"function": {
            				"name": "delay",
							"supports_parallel": false,
            				"description": "Use this tool to add a time delay between two tool calls.",
							"parameters": {
                				"type": "object",
								"properties": {
                					"delay": {
                    					"type": "number",
                    					"description": "Delay period in milliseconds" }
								},
                				"required": ["delay"]
							},
							"returns": {
								"type": "object",
								"properties": {
									"result": {
										"type": "string",
										"enum": ["success", "failed"]
									}
								}
							}
						}
					\}

\{
        				"type": "function",
        				"function": {
            				"name": "get_detected_objects",
							"supports_parallel": false,
            				"description": "Get a JSON list of the currently detected objects.  This tool is useful for finding the relative position of objects.",
							"returns": {
								"type": "array",
								"description": "An array of detected objects.",
								"items": {
									"type": "object",
									"properties": {
										"x": {
											"type": "number",
											"description": "X coordinate in meters (+ is forward)."
										},
										"y": {
											"type": "number",
											"description": "Y coordinate in meters (+ is to the left)"
										},
										"z": {
											"type": "number",
											"description": "Z coordinate in meters (+ is up)"
										},
										"object_class": {
											"type": "string",
											"description": "type of object"
										},
										"id": {
											"type": "number",
											"description": "tracking ID of the object"
										},
										"relative_yaw": {
											"type": "number",
											"description": "yaw of the object relative to the robot. If positive, then the object is to the left, and vice versa."
										},
										"distance": {
											"type": "number",
											"description": "Distance to the object in meters"
										}
									}
								}
							}
						}
					\}

\{
        				"type": "function",
        				"function": {
            				"name": "set_parallel_tool_mode",
							"supports_parallel": false,
            				"description": "Use this tool to select how to process parallel tool calls.",
							"parameters": {
								"type": "object",
								"properties": {
									"mode": {
										"type": "string",
										"enum": ["wait_all", "wait_one"],
										"description": "wait_all will wait for all parallel tools to finish. wait_one will wait until at least one tool finishes.  Example usage, if you want the success/failure of one tool to stop another one, use wait_one.  If you want all parallel tools to run to completion, use wait_all"
									}
								},
								"required": ["mode"]
							},
							"returns": {
								"type": "object",
								"properties": {
									"result": {
										"type": "string",
										"enum": ["success", "failed"]
									}
								}
							}
						}
					\}

\{
        				"type": "function",
        				"function": {
            				"name": "wait_for_object_detected",
							"supports_parallel": true,
            				"description": "Use this tool to wait for an object of the specified class to become detected.  This tool can be used in parallel with another tool to stop the other tool when a detection occurs such as when moving/rotating to find something.",
							"parameters": {
								"type": "object",
								"properties": {
									"obj_class": {
										"type": "string",
										"description": "Class type of object to be detected, supported types: person,cat."
									}
								},
								"required": ["obj_class"]
							},
							"returns": {
								"type": "object",
								"properties": {
									"result": {
										"type": "string",
										"enum": ["success", "failed", "preempted"],
										"description": "Success indicates an object was detected.  All other results - not detected"
									}
								}
							}
						}
					\}

\{
        				"type": "function",
        				"function": {
            				"name": "set_reasoning_mode",
							"supports_parallel": false,
            				"description": "Use this tool to enable or disable your reasoning (aka thinking) mode when instructed by the user.",
							"parameters": {
                				"type": "object",
								"properties": {
                					"enable_reasoning": {
                    					"type": "boolean",
                    					"description": "The reasoning mode:  true - enabled, false - disabled" }
								},
                				"required": ["enable_reasoning"]
							},
							"returns": {
								"type": "object",
								"properties": {
									"result": {
										"type": "string",
										"enum": ["success", "failed"]
									}
								}
							}
						}
					\}
